+                        continue;
+                    } else if j < arg.len() - 1 {
+                        break;
+                    } else {
+                        // `j == arg.len() - 1`
+                        skip_next = true;
+                    }
+                }
+            } else {
+                program_file = Some(arg.clone());
+                break;
+            }
+        }
+        if let Some(program_file) = program_file {
+            let mut path = PathBuf::from(program_file);
+            path.pop();
+            while !path.join("Project.toml").exists() && !path.join("JuliaProject.toml").exists() {
+                if !path.pop() {
+                    return None;
+                }
+            }
+            return Some(path);
